const ABOUT_TAGS = [
  { icon: <MsftIcon />, text: 'Microsoft Intern' },
  { icon: <UicIcon />, text: 'UIC Computer Science Alumni' },
  { icon: <MapPinIcon />, text: 'Based in Chicago' },
  { icon: <CodeIcon />, text: 'Web Developer' },
  { icon: <K8sIcon />, text: 'Azure Kubernetes Service' },
  { icon: <TeacherIcon />, text: 'Teaching Assistant' },
  { icon: <ReactIcon />, text: 'React Native & Next.js' },
  { icon: <CSharpIcon />, text: 'Go, C++, C#, TS' },
  { icon: <DotNetIcon />, text: 'ASP.NET Core & SQL' },
  { icon: <DockerIcon />, text: 'Docker & AWS' },
];

const revealVariants = {
  hidden: { opacity: 0, y: 26 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.7, ease: [0.16, 1, 0.3, 1] as const },
  },
};

export default function About() {
  const containerRef = useRef<HTMLElement>(null);
  
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start end", "end start"]
  });

  // Create slightly different vertical transforms for parallax depth.
  // We use 0.5 as the center point so they perfectly align to their natural grid
  // when the section is exactly in the center of the viewport, avoiding any overlaps.
  const y1 = useTransform(scrollYProgress, [0, 0.5, 1], [15, 0, -15]);
  const y2 = useTransform(scrollYProgress, [0, 0.5, 1], [5, 0, -5]);
  const y3 = useTransform(scrollYProgress, [0, 0.5, 1], [-5, 0, 5]);

  const getTransform = (i: number) => {
    if (i % 3 === 0) return y1;
    if (i % 3 === 1) return y2;
    return y3;
  };

  return (
    <section id="about-me" className={styles.container} ref={containerRef}>
      <motion.p
        className="eyebrow"
        variants={revealVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: 0.15 }}
      >
        01 — About
      </motion.p>

      <motion.h2
        id="about-heading"
        className={styles.heading}
        variants={revealVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: 0.15 }}
      >
        Hello, I am <span className={styles.hl}>Rafael Mejia.</span>
      </motion.h2>

      <motion.p
        className={styles.bodyText}
        variants={revealVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: 0.15 }}
      >
        I recently graduated from the <strong>University of Illinois Chicago</strong> with a degree in Computer Science. During my studies, I completed two software engineering internships at <strong>Microsoft</strong> in Redmond, where I worked on the Azure Kubernetes Service team. My time there gave me incredible exposure to cloud infrastructure, writing tools in Go for cluster control planes, and optimizing resources for machine learning workloads.
      </motion.p>

      <motion.p
        className={styles.bodyText}
        variants={revealVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: 0.15 }}
      >
        Outside of big tech, I actively work as a freelance developer building custom web applications and content management systems for small businesses. I also love diving deep into backend architecture, most recently building <strong>Ping</strong>, a large scale location based social app powered by React Native, ASP.NET Core, Redis, and PostgreSQL. When I am not writing code, you can usually find me lifting at the gym, experimenting with new recipes in the kitchen, or playing my guitar.
      </motion.p>

      <a
        className={styles.featureLink}
        href="https://drive.google.com/file/d/17RgR_8iTKqkB4IOh7xzZp4BmfJhAjxQL/view?usp=drive_link"
        target="_blank"
        rel="noopener noreferrer"
      >
        Resume{' '}
        <svg width="14" height="14" viewBox="0 0 16 16" fill="none">
          <path
            d="M4 12L12 4M6 4h6v6"
            stroke="currentColor"
            strokeWidth="1.6"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      </a>

      <motion.div
        className={styles.chips}
        variants={revealVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: 0.15 }}
      >
        {ABOUT_TAGS.map((tag, i) => (
          <motion.div 
            key={i} 
            className={styles.chipWrapper}
            style={{ y: getTransform(i) }}
          >
            <div className={styles.chipInner}>
              <span className={styles.k}>{tag.icon}</span> {tag.text}
            </div>
          </motion.div>
        ))}
      </motion.div>
    </section>
  );
}
